command:
// Sci-fi performance-enhancing — silver cybernetic xglow that drifts.
if (!game.modules.get("tokenmagic")?.active) return;
if (!token) return;
const filterId = "fishut-tmfx-scifi-performance-enhancing";
if (mode === "remove") { await TokenMagic.deleteFiltersOnToken(token, filterId); return; }
await TokenMagic.addUpdateFiltersOnToken(token, [{
  filterType: "xglow",
  filterId,
  color: 0xc0c0e0,
  thickness: 1,
  scale: 1.5,
  time: 0,
  animated: { time: { active: true, speed: 0.001, animType: "move" } }
}]);
